.darma-loader-darma-research-liquid-tab-switcher { --speed: var(--loader-speed, 1s); --accent: var(--loader-color, #06b6d4); --accent-2: var(--loader-secondary-color, #a855f7); width: calc(var(--loader-size, 70px) * 2.5); height: calc(var(--loader-size, 70px) * .52); min-width: 150px; padding: 5px; display: grid; grid-template-columns: repeat(3, 1fr); gap: 5px; border-radius: 999px; background: #0f172a; position: relative; overflow: hidden; box-shadow: inset 0 0 0 1px #fff2; }
.darma-loader-darma-research-liquid-tab-switcher span { border-radius: inherit; background: #ffffff12; z-index: 1; }
.darma-loader-darma-research-liquid-tab-switcher b { position: absolute; top: 5px; bottom: 5px; left: 5px; width: calc((100% - 20px) / 3); border-radius: 999px; background: linear-gradient(90deg, var(--accent), var(--accent-2)); box-shadow: 0 0 18px var(--accent); animation: darma-loader-darma-research-liquid-tab-switcher-tab-slide calc(var(--speed) * 1.8) cubic-bezier(.65,0,.35,1) infinite; }
@keyframes darma-loader-darma-research-liquid-tab-switcher-tab-slide { 0%,22% { transform: translateX(0); } 34%,56% { transform: translateX(calc(100% + 5px)); } 68%,90% { transform: translateX(calc(200% + 10px)); } 100% { transform: translateX(0); } }

